            aria-selected="false"
            tabindex="-1"
            onclick="formatCell(\'italic\')">
            <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24"
                 viewBox="0 0 24 24" fill="none" stroke="currentColor"
                 stroke-width="2" stroke-linecap="round" stroke-linejoin="round"
                 class="icon nav-link-icon icon-2">
              <path d="M11 5l6 0"></path>
              <path d="M7 19l6 0"></path>
              <path d="M14 5l-4 14"></path>
            </svg>
          </button>

          <!-- Color picker -->
          <button
            class="nav-link"
            aria-selected="false"
            tabindex="-1">
  
            <input
              type="color"
              id="cellTextColor"
              value="#000000"
              class="form-control form-control-color"
              title="Text Color"
              oninput="formatCell(\'foreColor\', this.value)">
          </button>

          <!-- Clear grid -->
          <button
            class="nav-link"
            role="tab"
            data-bs-toggle="tab"
            aria-selected="false"
            aria-disabled="true"
            tabindex="-1"
            onclick="clearGrid()">
            <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24"
                 viewBox="0 0 24 24" fill="none" stroke="currentColor"
                 stroke-width="2" stroke-linecap="round" stroke-linejoin="round"
                 class="icon nav-link-icon icon-2">
              <path d="M4 7l16 0" />
              <path d="M10 11l0 6" />
              <path d="M14 11l0 6" />
              <path d="M5 7l1 12a2 2 0 0 0 2 2h8a2 2 0 0 0 2 -2l1 -12" />
              <path d="M9 7v-3a1 1 0 0 1 1 -1h4a1 1 0 0 1 1 1v3" />
            </svg>
          </button>

          <!-- Insert table -->
          <button
            class="nav-link"
            role="tab"
            data-bs-toggle="tab"
            aria-selected="false"
            tabindex="-1"
            onclick="insertGeneratedTable()">
            <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24"
                 viewBox="0 0 24 24" fill="none" stroke="currentColor"
                 stroke-width="2" stroke-linecap="round" stroke-linejoin="round"
                 class="icon nav-link-icon icon-2">
              <path d="M12 5l0 14" />
              <path d="M5 12l14 0" />
            </svg>
          </button>
        </nav>

      <button
        type="button"
        class="btn-close"
        onclick="closeTableOverlay()"
        aria-label="Close">
      </button>
    </div>

    <!-- Body -->
    <div class="settings-body">
      <div
