          <h3>Copy project</h3>
          <button type="button" class="btn-close" onclick="closeCopyProjectOverlay()" aria-label="Close"></button>
        </div>
        <div class="settings-body" style="height: auto; overflow: visible;">
          <div class="settings-content" style="padding: 2rem;">
            <div class="mb-3">
