                            height = "56px",
                            resize = "none"
                          ),
                          actionButton(
                            "ai_send",
                            "",
                            icon = icon("arrow-up"),
                            class = "btn btn-primary btn-send"
                          )
                        ),

                        # Footer Controls
                        div(
                          class = "footer-controls d-flex justify-content-center align-items-center mt-3",
                          div(tags$small(
                            class = "text-muted",
                            style = "font-size: 0.8125rem; opacity: 0.8;",
                            "AI can make mistakes. Verify important information."
                          ))
                        )
                      )
                    ),

                    div(
                      id = "filesPane",
