                      div(
                        class = "pane-header",
                        style = "height: 38px; min-height: 38px; padding: 0 10px; display:flex; justify-content:space-between; align-items:center; border-bottom:1px solid var(--tblr-border-color);",
                        div(
                          style = "display:flex; align-items:center; gap:8px;",
                          # Collapse chevron
                          HTML(
                            '<button type="button"
                                              id="toggleFilesPane"
                                              class="btn-icon"
                                              title="Collapse files"
                                              style="color: var(--bs-secondary-color); background: none; border: none; padding: 0; cursor: pointer; font-size: 16px;">
                                              <i class="fa-solid fa-chevron-down" id="filesPaneChevron"></i>
                                           </button>'
                          ),
                          tags$strong(
                            "Files",
                            style = "font-size:14px; font-weight:600;"
                          )
                        ),
                        div(
                          style = "display:flex; gap:10px; align-items:center;",

                          HTML(
                            '<button class="rail-btn btn-icon"
                                                type="button"
                                                 onclick="openAddFilesOverlay(\'add-file-tab\')"
                                                 title="New File"
                                                 data-bs-toggle="tooltip"
                                                 data-bs-placement="bottom"
                                                 style="color: var(--bs-secondary-color); background: none; border: none;padding: 0;cursor: pointer;">
                                                <svg
                                                  xmlns="http://www.w3.org/2000/svg"
                                                  class="icon icon-1"
                                                  width="24"
                                                  height="24"
                                                  viewBox="0 0 24 24"
                                                  stroke-width="2"
                                                  stroke="currentColor"
                                                  fill="none"
                                                  stroke-linecap="round"
                                                  stroke-linejoin="round">
                                                    <path d="M14 3v4a1 1 0 0 0 1 1h4" />
                                                    <path d="M17 21h-10a2 2 0 0 1 -2 -2v-14a2 2 0 0 1 2 -2h7l5 5v11a2 2 0 0 1 -2 2z" />
                                                    <path d="M12 11l0 6" />
                                                    <path d="M9 14l6 0" />
                                                  </svg>
                                              </button>
                                              <button class="rail-btn btn-icon" 
                                                 type="button"
                                                 onclick="openAddFilesOverlay(\'add-folder-tab\')"
                                                 title="New Folder"
                                                 data-bs-toggle="tooltip"
                                                 data-bs-placement="bottom"
                                                 style="color: var(--bs-secondary-color); background: none; border: none;padding: 0;cursor: pointer;">
                                              <svg
                                                xmlns="http://www.w3.org/2000/svg"
                                                class="icon icon-1"
                                                width="24"
                                                height="24"
                                                viewBox="0 0 24 24"
                                                stroke-width="2"
                                                stroke="currentColor"
                                                fill="none"
                                                stroke-linecap="round"
                                                stroke-linejoin="round">
                                                 <path d="M12 19h-7a2 2 0 0 1 -2 -2v-11a2 2 0 0 1 2 -2h4l3 3h7a2 2 0 0 1 2 2v3.5" />
                                                 <path d="M16 19h6" />
                                                 <path d="M19 16v6" />
                                              </svg>
                                              </button>
                                              <button class="rail-btn btn-icon"
                                                 type="button"
                                                 onclick="openAddFilesOverlay(\'upload-tab\')"
                                                 title="Upload Files"
                                                 data-bs-toggle="tooltip"
                                                 data-bs-placement="bottom"
                                                 style="color: var(--bs-secondary-color); background: none; border: none;padding: 0;cursor: pointer;">
                                              <svg
                                                xmlns="http://www.w3.org/2000/svg"
                                                class="icon icon-1"
                                                width="24"
                                                height="24"
                                                viewBox="0 0 24 24"
                                                stroke-width="2"
                                                stroke="currentColor"
                                                fill="none"
                                                stroke-linecap="round"
                                                stroke-linejoin="round">
                                                  <path d="M4 17v2a2 2 0 0 0 2 2h12a2 2 0 0 0 2 -2v-2" />
                                                  <path d="M7 9l5 -5l5 5" />
                                                  <path d="M12 4l0 12" />
                                              </svg>
                                              </button>
