                                tags$i(class = "ti ti-check tick-icon"),
                                "Check syntax before compile"
                              ),
                              tags$label(
                                class = "dropdown-item",
                                tags$input(
                                  type = "radio",
                                  name = "syntaxCheck",
                                  value = "none",
                                  id = "syntaxCheckNone",
                                  checked = NA
                                ),
                                tags$i(class = "ti ti-check tick-icon"),
