      bio = "",
      profilePicture = "",
      verified = FALSE,
      collaborators = 0,
      memberSince = as.character(Sys.time()),
      lastActive = as.character(Sys.time())
    )
    jsonlite::write_json(
      defaultProfile,
      profilePath,
      auto_unbox = TRUE,
      pretty = TRUE
    )
  }
}

