    )
  })
  
  # Force them to update even if the menu is hidden or momentarily out of view
  outputOptions(output, "dashboardTitle", suspendWhenHidden = FALSE)
  outputOptions(output, "countActive", suspendWhenHidden = FALSE)
  outputOptions(output, "countArchived", suspendWhenHidden = FALSE)
  outputOptions(output, "countTrashed", suspendWhenHidden = FALSE) 
  

  output$totalFiles <- renderText({
    change_trigger <- projectChangeTrigger()
    projects <- loadProjects()
    if (length(projects) == 0) {
      return("0")
    }

    total <- 0
    for (proj in projects) {
      if (!is.null(proj$fileCount)) {
        count <- tryCatch(
          {
            as.integer(proj$fileCount)
          },
          error = function(e) 0
        )
        total <- total + count
      }
    }
    as.character(total)
  })

  output$lastActivity <- renderText({
    change_trigger <- projectChangeTrigger()
    projects <- loadProjects()
    if (length(projects) == 0) {
      return("Never")
    }

    latest <- ""
    for (proj in projects) {
      if (!is.null(proj$lastEdited) && is.character(proj$lastEdited)) {
        if (proj$lastEdited > latest || latest == "") {
          latest <- proj$lastEdited
        }
      }
    }

    if (latest == "") {
      return("Never")
    }

    if (nchar(latest) >= 10) {
      return(as.character(format(Sys.time(), "%B %d, %Y at %H:%M:%S")))
    }

    "Recent"
  })

  # Sort button observers
  observeEvent(input$sortLastEdited, {
    projectSort("lastEdited")
  })

  observeEvent(input$sortName, {
    projectSort("name")
  })

  observeEvent(input$sortCreated, {
    projectSort("created")
  })

  observeEvent(input$sortFileCount, {
    projectSort("fileCount")
  })

  # Update button active states based on current sort
  observeEvent(projectSort(), {
    current_sort <- projectSort()

    # Remove active class from all sort buttons first
    shinyjs::runjs(
      "
    document.querySelectorAll('.btn-sort').forEach(btn => {
      btn.classList.remove('active');
    });
  "
    )

    # Add some delay to ensure DOM is updated, then add active class
    shinyjs::delay(100, {
      button_selector <- switch(
        current_sort,
        "lastEdited" = "#sortLastEdited",
        "name" = "#sortName",
        "created" = "#sortCreated",
        "fileCount" = "#sortFileCount"
      )

      if (!is.null(button_selector)) {
        shinyjs::runjs(sprintf(
          "
        var btn = document.querySelector('%s');
        if (btn) {
          btn.classList.add('active');
          console.log('Activated button:', '%s');
        } else {
          console.log('Button not found:', '%s');
        }
      ",
          button_selector,
          button_selector,
          button_selector
        ))
      }
    })
  })

  # In your dynamic file observers section, modify the kebab menu handlers:
  # Dynamic file observers - only create once per file
  observeEvent(
    rv_files(),
    {
      items <- rv_files()
      projId <- activeProjectId()

      # Get list of files we've already created observers for
      existing <- createdObservers()

      # Find new files that need observers
      newFiles <- setdiff(items, existing)

      if (length(newFiles) > 0) {
        # Use lapply instead of a for loop.
        # This forces 'item' to be captured correctly for each specific file.
        new_handles_nested <- lapply(newFiles, function(item) {
          # List to collect observers for THIS specific file
          file_specific_observers <- list()

          safeId <- paste0(projId, "_", gsub("[^A-Za-z0-9]", "_", item))
          projDir <- getActiveProjectDir()

          if (!is.null(projDir)) {
            fullPath <- file.path(projDir, item)

            if (file.exists(fullPath)) {
              isDir <- file.info(fullPath)$isdir

              # ============ DOWNLOAD OBSERVER ============
              obs_dl <- observeEvent(
                input[[paste0("download_", safeId)]],
                {
                  if (isDir) {
                    # Folder Download Logic
                    zipName <- paste0(
                      safeId,
                      "_",
                      format(Sys.time(), "%Y%m%d_%H%M%S"),
                      ".zip"
                    )
                    zipPath <- file.path(projDir, zipName)

                    tryCatch(
                      {
                        files_in_folder <- list.files(
                          fullPath,
                          full.names = TRUE,
                          recursive = TRUE
                        )
                        if (length(files_in_folder) > 0) {
                          zip::zip(
                            zipPath,
                            files = files_in_folder,
                            root = fullPath,
                            mode = "cherry-pick"
                          )

                          uid <- isolate(user_session$user_info$user_id)
                          pid <- activeProjectId()
                          dlUrl <- file.path(
                            "project",
                            uid,
                            "projects",
                            pid,
                            zipName
                          )

                          shinyjs::runjs(sprintf(
                            "
                        var link = document.createElement('a');
                        link.href = '%s';
                        link.download = '%s';
                        document.body.appendChild(link);
                        link.click();
                        document.body.removeChild(link);
                      ",
                            dlUrl,
                            zipName
                          ))

                          showTablerAlert(
                            "success",
                            "Downloading folder",
                            "Folder download started",
                            5000
                          )

                          later::later(
                            function() {
                              if (file.exists(zipPath)) file.remove(zipPath)
                            },
                            5
                          )
                        }
                      },
                      error = function(e) {
                        showTablerAlert(
                          "danger",
                          "Error downloading folder",
                          paste("Download failed:", e$message),
                          5000
                        )
                      }
                    )
                  } else {
                    # Single File Download Logic
                    uid <- isolate(user_session$user_info$user_id)
                    pid <- activeProjectId()
                    dlUrl <- file.path("project", uid, "projects", pid, item)

                    # 'item' is now correctly frozen by lapply
                    shinyjs::runjs(sprintf(
                      "
                    var link = document.createElement('a');
                    link.href = '%s';
                    link.download = '%s';
                    document.body.appendChild(link);
                    link.click();
                    document.body.removeChild(link);
                  ",
                      dlUrl,
                      basename(item)
                    ))

                    showTablerAlert(
                      "success",
                      "Download started",
                      paste("Downloading", basename(item)),
                      5000
                    )
                  }
                },
                ignoreInit = TRUE,
                once = FALSE
              )

              file_specific_observers[[
                length(file_specific_observers) + 1
              ]] <- obs_dl

              # ============ RENAME TRIGGER OBSERVER ============
              obs_rn <- observeEvent(
                input[[paste0("rename_", safeId)]],
                {
                  session$sendCustomMessage(
                    "enableInlineRename",
                    list(path = item)
                  )
                },
                ignoreInit = TRUE,
                once = FALSE
              )

              file_specific_observers[[
                length(file_specific_observers) + 1
              ]] <- obs_rn

              # ============ CONFIRM RENAME OBSERVER ============
              obs_rn_confirm <- observeEvent(
                input[[paste0("confirmRename_", safeId)]],
                {
                  req(input[[paste0("confirmRename_", safeId)]]$newName)
                  newName <- trimws(
                    input[[paste0("confirmRename_", safeId)]]$newName
                  )

                  if (newName == "" || newName == basename(item)) {
                    return()
                  }

                  dirPart <- dirname(item)
                  newPath <- if (dirPart == ".") {
                    file.path(projDir, newName)
                  } else {
                    file.path(projDir, dirPart, newName)
                  }

                  if (file.exists(newPath)) {
                    showTablerAlert(
                      "warning",
                      "Name already exists",
                      "A file or folder with that name already exists in this project.",
                      5000
                    )
                  } else {
                    success <- file.rename(fullPath, newPath)
                    if (success) {
                      rv_files(getVisibleFiles(projDir))

                      if (!is.null(activeProjectId())) {
                        updateProjectFileCount(activeProjectId())
                      }

                      showTablerAlert(
                        "success",
                        "File renamed",
                        paste("File successfully renamed to", newName),
                        5000
                      )
                    } else {
                      showTablerAlert(
                        "danger",
                        "Error renaming file",
                        "Failed to rename file.",
                        5000
                      )
                    }
                  }
                },
                ignoreInit = TRUE,
                once = FALSE
              )

              file_specific_observers[[
                length(file_specific_observers) + 1
              ]] <- obs_rn_confirm

              # ============ DELETE TRIGGER OBSERVER ============
              obs_del <- observeEvent(
                input[[paste0("delete_", safeId)]],
                {
                  modalId <- paste0("deleteModal_", safeId)
                  itemType <- if (isDir) "folder" else "file"

                  modalHTML <- sprintf(
                    '
                <div class="modal modal-blur" id="%s" tabindex="-1" style="display: block;" aria-hidden="true" role="dialog">
                  <div class="modal-dialog modal-sm" role="document">
                    <div class="modal-content">
                      <button type="button" class="btn-close" data-bs-dismiss="modal" aria-label="Close"
                        onclick="document.getElementById(\'%s\').remove(); document.body.classList.remove(\'modal-open\'); var backdrop = document.querySelector(\'.modal-backdrop\'); if(backdrop) backdrop.remove();"></button>
                      <div class="modal-status bg-danger"></div>
                      <div class="modal-body text-center py-4">
                        <svg xmlns="http://www.w3.org/2000/svg" class="icon mb-2 text-danger icon-lg" width="24" height="24" viewBox="0 0 24 24" stroke-width="2" stroke="currentColor" fill="none" stroke-linecap="round" stroke-linejoin="round">
                          <path stroke="none" d="M0 0h24v24H0z" fill="none"/>
                          <path d="M12 9v2m0 4v.01"/>
                          <path d="M5 19h14a2 2 0 0 0 1.84 -2.75l-7.1 -12.25a2 2 0 0 0 -3.5 0l-7.1 12.25a2 2 0 0 0 1.75 2.75"/>
                        </svg>
                        <h3>Are you sure?</h3>
                        <div class="text-secondary">Do you really want to delete this %s <strong>%s</strong>? This cannot be undone.</div>
                      </div>
                      <div class="modal-footer">
                        <div class="w-100">
                          <div class="row">
                            <div class="col">
                              <button type="button" class="btn w-100" data-bs-dismiss="modal"
                                onclick="document.getElementById(\'%s\').remove(); document.body.classList.remove(\'modal-open\'); var backdrop = document.querySelector(\'.modal-backdrop\'); if(backdrop) backdrop.remove();">
                                Cancel
                              </button>
                            </div>
                            <div class="col">
                              <button type="button" class="btn btn-danger w-100"
                                onclick="
                                  Shiny.setInputValue(\'confirmDelete_%s\', Math.random(), {priority: \'event\'});
                                  document.getElementById(\'%s\').remove(); 
                                  document.body.classList.remove(\'modal-open\'); 
                                  var backdrop = document.querySelector(\'.modal-backdrop\'); 
                                  if(backdrop) backdrop.remove();
                                ">
                                Delete %s
                              </button>
                            </div>
                          </div>
                        </div>
                      </div>
                    </div>
                  </div>
                </div>
                ',
                    modalId,
                    modalId,
                    itemType,
                    basename(item),
                    modalId,
                    safeId,
                    modalId,
                    itemType
                  )

                  shinyjs::runjs(sprintf(
                    "
                  var existing = document.getElementById('%s');
                  if (existing) existing.remove();
                  var backdrop = document.querySelector('.modal-backdrop');
                  if (backdrop) backdrop.remove();
                  document.body.insertAdjacentHTML('beforeend', %s);
                  document.body.classList.add('modal-open');
                ",
                    modalId,
                    jsonlite::toJSON(modalHTML, auto_unbox = TRUE)
                  ))
                },
                ignoreInit = TRUE,
                once = FALSE
              )

              file_specific_observers[[
                length(file_specific_observers) + 1
              ]] <- obs_del

              # ============ CONFIRM DELETE OBSERVER ============
              obs_del_confirm <- observeEvent(
                input[[paste0("confirmDelete_", safeId)]],
                {
                  if (file.exists(fullPath)) {
                    if (isDir) {
                      unlink(fullPath, recursive = TRUE)
                    } else {
                      file.remove(fullPath)
                    }

                    rv_files(getVisibleFiles(projDir))

                    if (!is.null(activeProjectId())) {
                      updateProjectFileCount(activeProjectId())
                    }

                    showTablerAlert(
                      "success",
                      "File deleted",
                      paste(basename(item), "has been deleted successfully."),
                      5000
                    )
                  }
                },
                ignoreInit = TRUE,
                once = FALSE
              )

              file_specific_observers[[
                length(file_specific_observers) + 1
              ]] <- obs_del_confirm
            } # end if file exists
          } # end if projDir not null

          return(file_specific_observers)
        })

        # Flatten the list of lists returned by lapply
        new_handles_list <- unlist(new_handles_nested, recursive = FALSE)

        # Clean any NULLs (files that didn't exist)
        new_handles_list <- new_handles_list[!sapply(new_handles_list, is.null)]

        # Add the new observers to our reactive list of handles
        current_handles <- file_observer_handles()
        file_observer_handles(c(current_handles, new_handles_list))

        # Update the list of created observers (names)
        createdObservers(c(existing, newFiles))
      }
    },
    ignoreInit = TRUE
  )

  # Clear observer tracking when project changes
  observeEvent(
    activeProjectId(),
    {
      createdObservers(character(0))
    },
    priority = 1000
  ) # High priority to run first

  # =================== INLINE RENAME HANDLER ===================
  observeEvent(
    input$confirmInlineRename,
    {
      req(input$confirmInlineRename)

      data <- input$confirmInlineRename
      oldPathRel <- data$oldPath
      newName <- trimws(data$newName)

      projDir <- getActiveProjectDir()
      req(projDir)

      oldFullPath <- file.path(projDir, oldPathRel)

      # Calculate new relative path
      parentDir <- dirname(oldPathRel)
      if (parentDir == ".") {
        newPathRel <- newName
      } else {
        newPathRel <- file.path(parentDir, newName)
      }
      newFullPath <- file.path(projDir, newPathRel)

      # Validations
      if (!file.exists(oldFullPath)) {
        showTablerAlert("danger", "File not found", "Original file not found.", 5000)
        rv_files(getVisibleFiles(projDir))
        return()
      }

      if (file.exists(newFullPath)) {
        showTablerAlert(
          "warning",
          "Name already exists",
          "A file with that name already exists.",
          5000
        )
        rv_files(getVisibleFiles(projDir))
        return()
      }

      # Perform Rename
      success <- file.rename(oldFullPath, newFullPath)

      if (success) {
        # 1. Update Project Metadata (CRITICAL FIX for persistence)
        # If we renamed the mainFile, update projects.json so it loads correctly next time
        projects <- loadProjects()
        updatedMeta <- FALSE
        currentProjId <- activeProjectId()

        for (i in seq_along(projects)) {
          if (projects[[i]]$id == currentProjId) {
            # Check if the OLD path matches the stored mainFile
            if (
              !is.null(projects[[i]]$mainFile) &&
                projects[[i]]$mainFile == oldPathRel
            ) {
              projects[[i]]$mainFile <- newPathRel
              updatedMeta <- TRUE
            }
            break
          }
        }
        if (updatedMeta) {
          saveProjects(projects)
        }

        # 2. Update Active Editor State
        # If the file currently open is the one we renamed, point editor to new name
        if (currentFile() == oldPathRel) {
          currentFile(newPathRel)
          updateStatus(newPathRel)

          # Determine mode for the new name (e.g. if extension changed)
          newMode <- getAceModeFromExtension(newName)
          # We don't need to reload content (it's in RAM), just update mode
          shinyjs::runjs(sprintf(
            "var editor = ace.edit('sourceEditor'); editor.getSession().setMode('ace/mode/%s');",
            newMode
          ))
        }

        # 3. Refresh UI
        rv_files(getVisibleFiles(projDir))
        if (!is.null(activeProjectId())) {
          updateProjectFileCount(activeProjectId())
        }

        showTablerAlert(
          "success",
          "File renamed",
          paste("Renamed file to", newName),
          5000
        )
      } else {
        showTablerAlert("danger", "Error renaming file", "Failed to rename file.", 5000)
        rv_files(getVisibleFiles(projDir))
      }
    },
    once = FALSE
  )

  # Helper function to detect Ace mode from file extension
  getAceModeFromExtension <- function(filename) {
    ext <- tolower(tools::file_ext(filename))

    mode_map <- list(
      # LaTeX and related
      "tex" = "latex",
      "bib" = "bibtex",
      "rnw" = "latex",
      "bst" = "latex",
      "sty" = "latex",

      # Programming languages
      "r" = "r",
      "py" = "python",
      "js" = "javascript",
      "ts" = "typescript",
      "java" = "java",
      "c" = "c_cpp",
      "cpp" = "c_cpp",
      "cc" = "c_cpp",
      "cxx" = "c_cpp",
      "h" = "c_cpp",
      "hpp" = "c_cpp",
      "cs" = "csharp",
      "php" = "php",
      "rb" = "ruby",
      "go" = "golang",
      "rs" = "rust",
      "swift" = "swift",
      "kt" = "kotlin",
      "scala" = "scala",
      "sh" = "sh",
      "bash" = "sh",
      "zsh" = "sh",
      "fish" = "sh",
      "ps1" = "powershell",
      "pl" = "perl",
      "lua" = "lua",

      # Web technologies
      "html" = "html",
      "htm" = "html",
      "xml" = "xml",
      "css" = "css",
      "scss" = "scss",
      "sass" = "sass",
      "less" = "less",
      "json" = "json",
      "yaml" = "yaml",
      "yml" = "yaml",
      "toml" = "toml",

      # Markup and documentation
      "md" = "markdown",
      "markdown" = "markdown",
      "rst" = "rst",
      "txt" = "text",

      # Data formats
      "csv" = "text",
      "tsv" = "text",
      "sql" = "sql",

      # Configuration files
      "ini" = "ini",
      "cfg" = "ini",
      "conf" = "text",
      "properties" = "properties",

      # Others
      "dockerfile" = "dockerfile",
      "makefile" = "makefile",
      "gitignore" = "gitignore"
    )

    # Return the mode or default to text
    mode <- mode_map[[ext]]
    if (is.null(mode)) {
      return("text")
    }
    return(mode)
  }

  observeEvent(currentFile(), {
    session$sendCustomMessage("renderCommentMarkers", list())
    commentUpdate(commentUpdate() + 1)
  })

  # Handle file single-clicks (Robust Binary Detection & Enhanced Preview)
  observeEvent(input$fileClick, {
    req(input$fileClick$path)

    projectId <- activeProjectId()
    req(projectId)
    projDir <- getActiveProjectDir()
    filePath <- input$fileClick$path
    fullPath <- file.path(projDir, filePath)

    if (!file.exists(fullPath)) {
      return()
    }

    # --- 1. SAFETY CHECKS ---
    finfo <- file.info(fullPath)
    if (is.na(finfo$size)) {
      return()
    }

    # Guard: Prevent opening files > 5MB in the text editor
    is_too_large <- finfo$size > (5 * 1024 * 1024)

    ext <- tolower(tools::file_ext(filePath))
    isEditable <- isTRUE(input$fileClick$isEditable)

    # Comprehensive Binary Extensions List
    binary_exts <- c(
      # Documents & Office
      "pdf",
      "doc",
      "docx",
      "xls",
      "xlsx",
      "xlsm",
      "ppt",
      "pptx",
      "odt",
      "ods",
      "odp",
      "rtf",
      "epub",
      "pages",
      "key",
      "numbers",
      "vsd",
      "vsdx",
      # Images & Design
      "png",
      "jpg",
      "jpeg",
      "gif",
      "bmp",
      "tiff",
      "tif",
      "ico",
      "webp",
      "heic",
      "psd",
      "ai",
      "raw",
      "eps",
      "ps",
      "xcf",
      "indd",
      "cdr",
      "sketch",
      "fig",
      # Audio
      "mp3",
      "wav",
      "ogg",
      "m4a",
      "flac",
      "aac",
      "wma",
      "aiff",
      "mid",
      "midi",
      "opus",
      "pcm",
      # Video
      "mp4",
      "mov",
      "avi",
      "webm",
      "mkv",
      "flv",
      "wmv",
      "m4v",
      "3gp",
      "mpeg",
      "mpg",
      "m2ts",
      "mts",
      "vob",
      # Archives
      "zip",
      "tar",
      "gz",
      "tgz",
      "7z",
      "rar",
      "bz2",
      "xz",
      "iso",
      "dmg",
      "pkg",
      "z",
      "cab",
      "rpm",
      "deb",
      "img",
      "vhd",
      "vdi",
      "vmdk",
      # Fonts
      "woff",
      "woff2",
      "ttf",
      "eot",
      "otf",
      "pfb",
      "pfm",
      # Data & Science
      "parquet",
      "rds",
      "rdata",
      "rda",
      "feather",
      "fst",
      "avro",
      "h5",
      "hdf5",
      "nc",
      "fits",
      # Database
      "db",
      "sqlite",
      "sqlite3",
      "mdb",
      "accdb",
      "sqlitedb",
      "mdf",
      "ldf",
      # Executables
      "exe",
      "dll",
      "so",
      "dylib",
      "bin",
      "o",
      "obj",
      "pyc",
      "class",
      "jar",
      "war",
      "ear",
      "dat",
      "msi",
      "com",
      "apk",
      "ds_store",
      "thumbs.db",
      "lnk",
      # 3D
      "glb",
      "fbx",
      "blend",
      "3ds",
      "max",
      "c4d",
      "stl",
      "ply"
    )

    # --- CRITICAL FIX: TRUE BINARY DETECTION ---
    # Read the first 1024 bytes to check for NUL characters.
    # This prevents 'readLines' from crashing on files that look like text but aren't.
    is_binary_content <- tryCatch(
      {
        con <- file(fullPath, "rb")
        on.exit(close(con))
        bytes <- readBin(con, "raw", n = 1024)
        any(bytes == 00)
      },
      error = function(e) TRUE
    ) # Assume binary on error

    # Determine if we should open in Ace Editor
    # Must be: Editable flag + Not in binary list + No NUL bytes detected
    should_open_editor <- isEditable &&
      !(ext %in% binary_exts) &&
      !is_binary_content

    if (should_open_editor) {
      # ================= EDITABLE TEXT FILE =================

      if (is_too_large) {
        showTablerAlert(
          "warning",
          "File too large",
          "This file is too large to edit directly (> 5MB).", 5000)
        return()
      }

      # 1. Clear Old Markers & UI
      session$sendCustomMessage("clearLocalAnchors", list())
      session$sendCustomMessage("hideFilePreview", list(path = filePath))

      # 2. Safe Read
      content <- tryCatch(
        {
          paste(readLines(fullPath, warn = FALSE), collapse = "\n")
        },
        error = function(e) {
          showTablerAlert(
            "danger",
            "Read error",
            paste("Could not read file:", e$message)
          )
          return(NULL)
        }
      )

      if (is.null(content)) {
        return()
      }

      aceMode <- getAceModeFromExtension(filePath)

      # 3. SAFE LOAD
      session$sendCustomMessage(
        "cmdSafeLoadFile",
        list(
          content = content,
          mode = aceMode
        )
      )

      # 4. Update State
      currentFile(filePath)
      updateStatus(filePath)

      if (ext == "tex") {
        if (
          is.null(input$fileClick$context) ||
            input$fileClick$context != "synctex"
        ) {
          updateSelectInput(session, "compileMainFile", selected = filePath)
        }
      }

      # 5. Restore Comments & Cursor
      later::later(
        function() {
          isolate({
            specificComments <- loadComments(projectId, filePath)
            session$sendCustomMessage(
              "renderCommentMarkers",
              list(
                comments = specificComments,
                force = TRUE
              )
            )
            rv$fileJustLoaded <- TRUE

            savedRow <- 0
            savedCol <- 0
            projects <- loadProjects()
            for (p in projects) {
              if (p$id == projectId) {
                if (!is.null(p$cursorRow)) {
                  savedRow <- p$cursorRow
                }
                if (!is.null(p$cursorCol)) {
                  savedCol <- p$cursorCol
                }
                break
              }
            }

            if (!is.null(input$fileClick$gotoLine)) {
              session$sendCustomMessage(
                'aceGoTo',
                list(line = as.numeric(input$fileClick$gotoLine))
              )
            } else {
              session$sendCustomMessage(
                'cursorRestore',
                list(file = filePath, row = savedRow, column = savedCol)
              )
            }

            commentUpdate(commentUpdate() + 1)
          })
        },
        delay = 0.25
      )
    } else {
      # ================= PREVIEW / BINARY =================

      uid <- isolate(user_session$user_info$user_id)
      pUrl <- file.path("project", uid, "projects", projectId, filePath)

      if (ext %in% c("png", "jpg", "jpeg", "gif", "svg", "webp", "bmp")) {
        session$sendCustomMessage(
          "showFilePreview",
          list(
            filename = basename(filePath),
            type = "image",
            url = pUrl,
            relPath = filePath
          )
        )
      } else if (ext == "pdf") {
        pUrl <- paste0(pUrl, "?t=", as.numeric(Sys.time()))
        session$sendCustomMessage(
          "showFilePreview",
          list(
            filename = basename(filePath),
            type = "pdf",
            url = pUrl,
            relPath = filePath
          )
        )
      } else if (ext %in% c("mp4", "webm", "ogg", "mov")) {
        session$sendCustomMessage(
          "showFilePreview",
          list(
            filename = basename(filePath),
            type = "video",
            url = pUrl,
            relPath = filePath
          )
        )
      } else if (ext %in% c("mp3", "wav")) {
        session$sendCustomMessage(
          "showFilePreview",
          list(
            filename = basename(filePath),
            type = "audio",
            url = pUrl,
            relPath = filePath
          )
        )
      } else {
        # FALLBACK: Unknown type or explicit binary
        # Only try to read as text if we CONFIRMED it is NOT binary and is small
        if (!is_binary_content && finfo$size < 500 * 1024) {
          content <- tryCatch(
            {
              paste(readLines(fullPath, warn = FALSE), collapse = "\n")
            },
            error = function(e) "File cannot be previewed."
          )

          session$sendCustomMessage(
            "showFilePreview",
            list(
              filename = basename(filePath),
              type = "text",
              content = content
            )
          )
        } else {
          session$sendCustomMessage(
            "showFilePreview",
            list(
              filename = basename(filePath),
              type = "text",
              content = "File cannot be previewed as text."
            )
          )
        }
      }

      shinyjs::runjs(
        "
        if (document.getElementById('historyOverlay') && document.getElementById('historyOverlay').classList.contains('show')) {
          Shiny.setInputValue('openHistoryBtn', Math.random(), {priority: 'event'});
        }
      "
      )
    }
  })

  # --- NEW HELPER: Save Main File Preference ---
  updateProjectMainFilePreference <- function(projectId, filename) {
    req(projectId, filename)
    projects <- loadProjects()
    updated <- FALSE

    if (length(projects) > 0) {
      for (i in seq_along(projects)) {
        if (projects[[i]]$id == projectId) {
          # Only save if different to avoid disk churn
          if (
            is.null(projects[[i]]$mainFile) ||
              projects[[i]]$mainFile != filename
          ) {
            projects[[i]]$mainFile <- filename
            projects[[i]]$lastEdited <- as.character(Sys.time())
            updated <- TRUE
          }
          break
        }
      }
      if (updated) saveProjects(projects)
    }
  }

  # ---------------- CURSOR PERSISTENCE (SERVER SIDE) ----------------
  # Debounce inputs to write to disk max once every 2 seconds
  cursor_debounced <- reactive({
    input$cursorPosition
  }) %>%
    debounce(2000)

  observeEvent(cursor_debounced(), {
    req(activeProjectId())
    pos <- cursor_debounced()

    # Only save if coordinates are valid numbers
    if (!is.null(pos$row) && !is.null(pos$column)) {
      projects <- loadProjects()
      updated <- FALSE

      for (i in seq_along(projects)) {
        if (projects[[i]]$id == activeProjectId()) {
          # Update the list in memory
          projects[[i]]$cursorRow <- pos$row
          projects[[i]]$cursorCol <- pos$column
          updated <- TRUE
          break
        }
      }

      if (updated) {
        saveProjects(projects)
      }
    }
  })

  # Function to find .bib files referenced in main .tex file
  findBibFiles <- function(texContent, projDir) {
    if (is.null(texContent) || !nzchar(texContent)) {
      return(character(0))
    }

    bibFiles <- character(0)

    # Check for \bibliography{} command
    bibMatches <- gregexpr(
      "\\\\bibliography\\{([^}]+)\\}",
      texContent,
      perl = TRUE
    )
    if (bibMatches[[1]][1] != -1) {
      bibStrs <- regmatches(texContent, bibMatches)[[1]]
      for (bibStr in bibStrs) {
        bibNames <- sub(
          "\\\\bibliography\\{([^}]+)\\}",
          "\\1",
          bibStr,
          perl = TRUE
        )
        bibNames <- strsplit(bibNames, ",")[[1]]
        bibNames <- trimws(bibNames)

        for (bibName in bibNames) {
          if (!grepl("\\.bib$", bibName, ignore.case = TRUE)) {
            bibName <- paste0(bibName, ".bib")
          }
          bibPath <- file.path(projDir, bibName)
          if (file.exists(bibPath)) {
            bibFiles <- c(bibFiles, bibName)
          }
        }
      }
    }

    # Check for \addbibresource{} (biblatex)
    addbibMatches <- gregexpr(
      "\\\\addbibresource\\{([^}]+)\\}",
      texContent,
      perl = TRUE
    )
    if (addbibMatches[[1]][1] != -1) {
      addbibStrs <- regmatches(texContent, addbibMatches)[[1]]
      for (addbibStr in addbibStrs) {
        bibName <- sub(
          "\\\\addbibresource\\{([^}]+)\\}",
          "\\1",
          addbibStr,
          perl = TRUE
        )
        bibName <- trimws(bibName)

        if (!grepl("\\.bib$", bibName, ignore.case = TRUE)) {
          bibName <- paste0(bibName, ".bib")
        }
        bibPath <- file.path(projDir, bibName)
        if (file.exists(bibPath)) {
          bibFiles <- c(bibFiles, bibName)
        }
      }
    }

    # If no explicit references, look for any .bib files in project
    if (length(bibFiles) == 0) {
      allBibFiles <- list.files(
        projDir,
        pattern = "\\.bib$",
        ignore.case = TRUE,
        recursive = TRUE
      )
      if (length(allBibFiles) > 0) {
        bibFiles <- allBibFiles
      }
    }

    return(unique(bibFiles))
  }

  # Function to parse .bib file and extract citation keys
  parseBibFile <- function(bibPath) {
    if (!file.exists(bibPath)) {
      return(character(0))
    }

    content <- paste(readLines(bibPath, warn = FALSE), collapse = "\n")

    if (!nzchar(trimws(content))) {
      return(character(0))
    }

    # Match @article, @book, etc. with their keys
    pattern <- "@\\w+\\s*\\{\\s*([^,\\s]+)"
    matches <- gregexpr(pattern, content, perl = TRUE)

    if (matches[[1]][1] == -1) {
      return(character(0))
    }

    keys <- character(0)
    matchData <- regmatches(content, matches)[[1]]

    for (match in matchData) {
      key <- sub("@\\w+\\s*\\{\\s*([^,\\s]+)", "\\1", match, perl = TRUE)
      keys <- c(keys, trimws(key))
    }

    return(unique(keys))
  }

  # Function to parse LaTeX content and extract label keys
  parseLabelsFromContent <- function(content) {
    if (is.null(content) || !nzchar(trimws(content))) {
      return(character(0))
    }

    labels <- character(0)

    # Match \label{key} patterns
    pattern <- "\\\\label\\{([^}]+)\\}"
    matches <- gregexpr(pattern, content, perl = TRUE)

    if (matches[[1]][1] == -1) {
      return(character(0))
    }

    matchData <- regmatches(content, matches)[[1]]

    for (match in matchData) {
      key <- sub("\\\\label\\{([^}]+)\\}", "\\1", match, perl = TRUE)
      labels <- c(labels, trimws(key))
    }

    return(unique(labels))
  }

  # ---------------- HELPER: PUSH BIB CITATIONS TO JS ----------------
  pushBibCitations <- function(texContent, projDir) {
    # 0. Reset to 0 initially
    session$sendCustomMessage("updateCitationCount", 0)

    # 1. Find .bib files referenced in the content
    bibFiles <- findBibFiles(texContent, projDir)

    # 2. If no files found, clear the JS array and exit
    if (length(bibFiles) == 0) {
      shinyjs::runjs(
        "if (window.updateBibEntries) window.updateBibEntries([]);"
      )
      # Explicitly ensure count stays at 0
      session$sendCustomMessage("updateCitationCount", 0)
      return()
    }

    # 3. Parse all found .bib files
    allKeys <- character(0)
    for (bibFile in bibFiles) {
      bibPath <- file.path(projDir, bibFile)
      keys <- parseBibFile(bibPath)
      allKeys <- c(allKeys, keys)
    }

    allKeys <- unique(allKeys)

    # 4. Push directly to JavaScript
    keysJSON <- jsonlite::toJSON(allKeys, auto_unbox = TRUE)
    shinyjs::runjs(sprintf(
      "if (window.updateBibEntries) window.updateBibEntries(%s);",
      keysJSON
    ))

    # 5. Update the visual counter with the final length (even if 0)
    session$sendCustomMessage("updateCitationCount", length(allKeys))
  }

  # ---------------- HELPER: PUSH LABEL KEYS TO JS ----------------
  pushLabelKeys <- function(texContent) {
    # 0. Reset to 0 initially
    session$sendCustomMessage("updateLabelCount", 0)

    # 1. Parse labels from content
    allKeys <- parseLabelsFromContent(texContent)

    # 2. If no labels found, clear the JS array and exit
    if (length(allKeys) == 0) {
      shinyjs::runjs(
        "if (window.updateLabelEntries) window.updateLabelEntries([]);"
      )
      # Explicitly ensure count stays at 0
      session$sendCustomMessage("updateLabelCount", 0)
      return()
    }

    # 3. Push directly to JavaScript
    keysJSON <- jsonlite::toJSON(allKeys, auto_unbox = TRUE)
    shinyjs::runjs(sprintf(
      "if (window.updateLabelEntries) window.updateLabelEntries(%s);",
      keysJSON
    ))

    # 4. Update the visual counter with the final length
    session$sendCustomMessage("updateLabelCount", length(allKeys))
  }

