  # --- MODIFIED: Main TEX selector ---
  output$mainFileSelect <- renderUI({
    # CRITICAL: Depend on rv_files() so the dropdown rebuilds when files are added
    trigger <- rv_files()

    projDir <- getActiveProjectDir()
    if (is.null(projDir)) {
      return(p("No project loaded."))
    }

    # Get .tex files
    texFiles <- list.files(
      projDir,
      pattern = "\\.tex$",
      ignore.case = TRUE,
      recursive = TRUE
    )

    if (length(texFiles) > 0) {
      # 1. Determine the best default selection
      projects <- loadProjects()
      projId <- activeProjectId()
      savedMain <- NULL

      # Look for saved preference
      if (!is.null(projId)) {
        for (p in projects) {
          if (p$id == projId) {
            savedMain <- p$mainFile
            break
          }
        }
      }

      # Priority: Saved Preference -> First .tex file found
      # Since createNewFileTrigger now saves the preference immediately,
      # this will pick up the new file automatically when it re-renders.
      selectedFile <- if (!is.null(savedMain) && savedMain %in% texFiles) {
        savedMain
      } else {
        texFiles[1]
      }

      selectInput(
        "compileMainFile",
        "Selected main .tex",
        choices = texFiles,
        selected = selectedFile
      )
    } else {
      p("No .tex files available.")
    }
  })

  # When a .tex file is loaded, update activeProjectId based on the most recent 'lastEdited' timestamp
  # --- MODIFIED: Main File Dropdown Observer ---
  observeEvent(input$compileMainFile, {
    req(input$compileMainFile)
    projDir <- getActiveProjectDir()
    req(projDir)

    fileName <- input$compileMainFile
    filePath <- file.path(projDir, fileName)

    # 1. Update Preference (Remember this choice)
    if (!is.null(activeProjectId())) {
      updateProjectMainFilePreference(activeProjectId(), fileName)
    }

    # 2. CIRCUIT BREAKER: Stop the loop.
    # If the editor already has this file open, STOP.
    if (currentFile() == fileName) {
      return()
    }

    # 3. Load Content if file exists
    if (file.exists(filePath)) {
      content <- paste(readLines(filePath, warn = FALSE), collapse = "\n")
      aceMode <- getAceModeFromExtension(fileName)

      # THIS IS THE FIX: Load content + Wipe Undo History
      session$sendCustomMessage(
        "cmdSafeLoadFile",
        list(
          content = content,
          mode = aceMode
        )
      )

      currentFile(fileName)
      updateStatus(fileName)
      session$sendCustomMessage(
        "cursorRestore",
        list(file = isolate(currentFile()))
      )
      pushBibCitations(content, projDir)
      pushLabelKeys(content)
    }
  })

  # =================== TABLER MODAL HANDLERS ===================

  # New File Handler (Updated for Overlay)
  observeEvent(
    input$createNewFileTrigger,
    {
      req(input$createNewFileTrigger$name)

      # Check if type is provided; if not, extract it from name
      rawName <- trimws(input$createNewFileTrigger$name)
      suppliedType <- input$createNewFileTrigger$type

      if (is.null(suppliedType) || suppliedType == "") {
        # User typed full name (e.g., "script.R")
        fileExtension <- paste0(".", tools::file_ext(rawName))
        fileName <- tools::file_path_sans_ext(rawName)

        # If no extension was typed, default to .tex
        if (fileExtension == ".") {
          fileExtension <- ".tex"
          fileName <- rawName
        }
        fileType <- fileExtension
      } else {
        # Fallback for old behavior if needed
        fileName <- rawName
        fileType <- suppliedType
      }

      projDir <- getActiveProjectDir()
      req(projDir)

      # Ensure unique naming for common names
      if (
        fileName %in%
          c("main", "document", "paper", "thesis") &&
          fileType == ".tex"
      ) {
        # Check if specific file exists before appending timestamp
        if (file.exists(file.path(projDir, paste0(fileName, fileType)))) {
          fileName <- paste0(fileName, "_", format(Sys.time(), "%Y%m%d_%H%M%S"))
        }
      }

      new_name <- paste0(fileName, fileType)
      new_path <- file.path(projDir, new_name)

      if (file.exists(new_path)) {
        showTablerAlert(
          "warning",
          "File already exists",
          paste("A file named", new_name, "already exists."),
          5000
        )
      } else {
        # Create file with template content based on type
        content <- switch(
          fileType,
          ".tex" = paste(
            "\\documentclass{article}",
            "\\title{Your LaTeX Document}",
            "\\author{User}",
            "\\date{\\today}",
            "",
            "\\begin{document}",
            "\\maketitle",
            "",
            "\\section{Introduction}",
            "Start writing here.",
            "",
            "\\end{document}",
            sep = "\n"
          ),
          ".bib" = paste(
            "@article{example2025,",
            "  author = {Smith, John},",
            "  title = {Example Title},",
            "  journal = {Journal of Examples},",
            "  year = {2025}",
            "}",
            sep = "\n"
          ),
          "" # Empty for other types
        )

        writeLines(content, new_path)
        rv_files(getVisibleFiles(projDir))

        # Load the new file into editor
        updateAceEditor(session, "sourceEditor", value = content)
        currentFile(new_name)
        updateStatus(paste0(new_name, " created"))
        session$sendCustomMessage('cursorRestore', list(file = new_name))

        # If the new file is a .tex file, force it to be the main project file immediately
        if (fileType == ".tex") {
          updateProjectMainFilePreference(activeProjectId(), new_name)
          # Force UI update immediately so compile button works right away
          updateSelectInput(session, "compileMainFile", selected = new_name)
        }

        showTablerAlert(
          "success",
          "File created",
          paste("Successfully created", new_name),
          5000
        )

        if (!is.null(activeProjectId())) {
          updateProjectFileCount(activeProjectId())
        }
      }
    },
    ignoreInit = TRUE
  )

  # New Folder Handler
