  #Name of active project
  getProjectNameById <- function(pid) {
    if (is.null(pid) || !nzchar(pid)) {
      return("")
    }
    projs <- loadProjects()
    if (!length(projs)) {
      return("")
    }
    for (p in projs) {
      if (is.list(p) && identical(p$id, pid)) return(p$name %||% "")
    }
    ""
  }
