  # ----------------------------- FILE SEARCH SERVER LOGIC -----------------------------

  observeEvent(input$fileSearchQuery, {
    query <- input$fileSearchQuery

    # UI Element for Results
    output$fileSearchResults <- renderUI({
      if (is.null(query) || nchar(trimws(query)) < 2) {
        return(div(
          style = "text-align:center; color:var(--bs-secondary-color); padding-top:20px;",
          div(
            class = "empty",
            ui_success_illustration(),
            HTML(
              '
                         <p class="empty-title">EMPTY SEARCH</p>
                         <p class="empty-subtitle text-secondary">Type at least 2 characters to search.</p>
            '
            )
          )
        ))
      }

      projDir <- getActiveProjectDir()
      if (is.null(projDir)) {
        return(NULL)
      }

      # 1. Get all files
      all_files <- list.files(projDir, recursive = TRUE)
      # Exclude cache, chat_files, and hidden files
      all_files <- all_files[
        !grepl("^(compiled_cache|chat_files|history)/|/\\.", all_files)
      ]

      results_html <- list()

      # Pre-compile regex for case-insensitive search
      safe_query <- gsub("([.|()\\^{}+$*?]|\\[|\\])", "\\\\\\1", query)

      # Define what we consider "Editable" (Text files) vs "Previewable" (Binary)
      # This prevents the app from crashing by trying to load a PNG into Ace Editor
      editable_exts <- c(
        "tex",
        "bib",
        "bst",
        "cls",
        "sty",
        "txt",
        "rnw",
        "md",
        "json",
        "xml",
        "html",
        "js",
        "css",
        "r",
        "py",
        "sh",
        "yaml",
        "yml",
        "csv"
      )

      for (file_rel in all_files) {
        full_path <- file.path(projDir, file_rel)
        file_name <- basename(file_rel)
        ext <- tolower(tools::file_ext(file_name))

        # Determine if this file should open in Editor (true) or Preview (false)
        is_editable_logical <- ext %in% editable_exts
        is_editable_js <- if (is_editable_logical) "true" else "false"

        matches_found <- FALSE
        snippets <- list()

        # A. CHECK FILENAME
        if (grepl(safe_query, file_name, ignore.case = TRUE)) {
          matches_found <- TRUE
        }

        # B. CHECK CONTENT (Only for editable text extensions)
        if (is_editable_logical && file.size(full_path) < 1024 * 1024 * 10) {
          # Skip files > 10MB

          lines <- tryCatch(
            readLines(full_path, warn = FALSE),
            error = function(e) NULL
          )

          if (!is.null(lines)) {
            match_indices <- grep(safe_query, lines, ignore.case = TRUE)

            if (length(match_indices) > 0) {
              matches_found <- TRUE

              # Limit matches
              display_indices <- head(match_indices, 99)

              for (idx in display_indices) {
                line_content <- lines[idx]

                # Truncate
                if (nchar(line_content) > 100) {
                  m_pos <- regexpr(
                    safe_query,
                    line_content,
                    ignore.case = TRUE
                  )[1]
                  start <- max(1, m_pos - 40)
                  end <- min(nchar(line_content), m_pos + 60)
                  line_content <- paste0(
                    "...",
                    substr(line_content, start, end),
                    "..."
                  )
                }

                # Highlight
                m <- gregexpr(safe_query, line_content, ignore.case = TRUE)
                regmatches(line_content, m) <- lapply(
                  regmatches(line_content, m),
                  function(x) {
                    paste0('<span class="search-highlight">', x, '</span>')
                  }
                )

                # SNIPPET CLICK: Passes 'gotoLine' to jump specific position
                snippets[[length(snippets) + 1]] <- div(
                  class = "search-result-snippet",
                  onclick = sprintf(
                    "
                    // Open file AND go to line
                    if (window.Shiny) Shiny.setInputValue('fileClick', {path: '%s', isEditable: true, gotoLine: %d, nonce: Math.random()}, {priority: 'event'});
                  ",
                    file_rel,
                    idx - 1
                  ), # Ace is 0-indexed
                  span(class = "snippet-line-num", idx),
                  span(class = "snippet-content", HTML(line_content))
                )
              }

              if (length(match_indices) > 99) {
                snippets[[length(snippets) + 1]] <- div(
                  class = "search-result-snippet",
                  style = "font-style: italic;",
                  paste0("...and ", length(match_indices) - 99, " more matches")
                )
              }
            }
          }
        }

        # C. BUILD RESULT CARD
        if (matches_found) {
          file_icon <- getFileIcon(file_name)

          # FILENAME CLICK: Uses calculated 'is_editable_js' to prevent crashing on binaries
          card <- div(
            class = "search-result-group",
            div(
              class = "search-result-file",
              onclick = sprintf(
                "
                            if (window.Shiny) Shiny.setInputValue('fileClick', {path: '%s', isEditable: %s, nonce: Math.random()}, {priority: 'event'});
                          ",
                file_rel,
                is_editable_js
              ),
              file_icon,
              span(file_rel)
            ),
            if (length(snippets) > 0) {
              div(class = "search-result-snippets", snippets)
            }
          )
          results_html[[length(results_html) + 1]] <- card
        }
      }

      if (length(results_html) == 0) {
        return(div(
          style = "text-align:center; padding:20px; color:var(--bs-secondary-color);",
          div(
            class = "empty",
            ui_empty_illustration(),
            HTML(
              '
                         <p class="empty-title">NO MATCHES FOUND</p>
                         <p class="empty-subtitle text-secondary">Search query produced 0 matches.</p>
            '
            )
          )
        ))
      }

      tagList(results_html)
    })
  })

  # --- SERVER SIDE REVIEW & COMMENTS LOGIC ---

  # commentUpdate <- reactiveVal(0) # Moved to top
  reviewPaneVisible <- reactiveVal(FALSE)

  # Optimized Load/Save with Validations
  loadComments <- function(projId, filePath) {
    uid <- isolate(user_session$user_info$user_id)
    if (
      is.null(uid) || is.null(projId) || is.null(filePath) || filePath == ""
    ) {
      return(list())
    }

    # Sanitize path for storage
    safeProj <- gsub("[^a-zA-Z0-9]", "_", projId)
    safePath <- gsub("[^a-zA-Z0-9]", "_", basename(filePath))

    cDir <- getUserCommentsDir(uid)
    if (is.null(cDir)) {
      return(list())
    }

    f <- file.path(cDir, paste0(safeProj, "_", safePath, ".json"))

    if (file.exists(f)) {
      tryCatch(
        {
          res <- jsonlite::fromJSON(f, simplifyVector = FALSE)
          # VALIDATION: Ensure res is a list and ONLY contains lists (comments)
          if (!is.list(res)) {
            return(list())
          }
          # Filter out any atomic vectors (corrupted entries) to prevent $ operator error
          res <- Filter(function(x) is.list(x) || is.environment(x), res)
          return(res)
        },
        error = function(e) list()
      )
    } else {
      list()
    }
  }

  # Recursive function to find parent ID and add reply
  add_reply_recursive <- function(nodes, parentId, newReply) {
    lapply(nodes, function(node) {
      # Check if this node is the parent (either a Comment or a Reply)
      if (node$id == parentId) {
        if (is.null(node$replies)) {
          node$replies <- list()
        }
        node$replies <- c(node$replies, list(newReply))
      } else {
        # If this node has children, search them recursively
        if (!is.null(node$replies) && length(node$replies) > 0) {
          node$replies <- add_reply_recursive(node$replies, parentId, newReply)
        }
      }
      node
    })
  }

  # Recursive function to delete a reply
  delete_reply_recursive <- function(nodes, targetId) {
    # First, filter out the target reply at this level
    nodes <- Filter(function(node) node$id != targetId, nodes)

    # Then recursively process any children
    lapply(nodes, function(node) {
      if (!is.null(node$replies) && length(node$replies) > 0) {
        node$replies <- delete_reply_recursive(node$replies, targetId)
      }
      node
    })
  }

  # Recursive function to set edit mode for a reply
  edit_reply_recursive <- function(nodes, targetId, isEditing = TRUE) {
    lapply(nodes, function(node) {
      if (node$id == targetId) {
        node$isEditing <- isEditing
      } else if (!is.null(node$replies) && length(node$replies) > 0) {
        node$replies <- edit_reply_recursive(node$replies, targetId, isEditing)
      }
      node
    })
  }

  # Recursive function to save edited reply content
  save_reply_recursive <- function(nodes, targetId, content) {
    lapply(nodes, function(node) {
      if (node$id == targetId) {
        node$content <- content
        node$isEditing <- FALSE
        # Edit time removed
      } else if (!is.null(node$replies) && length(node$replies) > 0) {
        node$replies <- save_reply_recursive(node$replies, targetId, content)
      }
      node
    })
  }

  saveComments <- function(projId, filePath, comments) {
    uid <- isolate(user_session$user_info$user_id)
    if (is.null(uid) || is.null(projId) || is.null(filePath)) {
      return()
    }

    safeProj <- gsub("[^a-zA-Z0-9]", "_", projId)
    safePath <- gsub("[^a-zA-Z0-9]", "_", basename(filePath))

    cDir <- getUserCommentsDir(uid)
    if (is.null(cDir)) {
      return()
    }

    f <- file.path(cDir, paste0(safeProj, "_", safePath, ".json"))

    # Ensure atomic write to prevent corruption
    jsonlite::write_json(comments, f, auto_unbox = TRUE, pretty = TRUE)
  }

