  # Ensure comments/highlights render even if pane is initially closed
  outputOptions(output, "commentStream", suspendWhenHidden = FALSE)

  # --- 6. COORDINATE SYNC (PERSISTENCE FIX) ---
  observeEvent(
    input$updateCommentCoordinates,
    {
      # 1. STATE CHECK (The Fix)
      # If the editor is not effectively active, IGNORE this update completely.
      # We do NOT reset this flag here. It stays FALSE until a project is loaded.
      if (isFALSE(rv$editor_active)) {
        return()
      }

      # 2. LEGACY FLAG CHECK (Optional, keep if you use it elsewhere)
      if (isTRUE(rv$block_comment_update)) {
        rv$block_comment_update <- FALSE
        return()
      }

      raw_input <- input$updateCommentCoordinates

      # 3. GARBAGE DATA CHECK (Double safety)
      # When editor hides, Ace often sends "[]" or empty strings.
      if (
        !is.null(raw_input) && is.character(raw_input) && length(raw_input) == 1
      ) {
        if (raw_input == "[]" || raw_input == "") return()
      }

      cat(
        "DEBUG: raw_input type =",
        class(raw_input),
        "| length =",
        length(raw_input),
        "\n"
      )
      if (length(raw_input) > 0) {
        cat("DEBUG: first element preview:", substr(raw_input[1], 1, 80), "\n")
      }

      # ONLY accept if it's a single JSON string
      if (!is.character(raw_input) || length(raw_input) != 1) {
        return()
      }

      json_str <- trimws(raw_input[1])
      if (nchar(json_str) == 0 || json_str == "[]") {
        return()
      }

      # Parse JSON
      updates <- tryCatch(
        {
          jsonlite::fromJSON(json_str, simplifyVector = FALSE)
        },
        error = function(e) {
          return(NULL)
        }
      )

      if (is.null(updates) || length(updates) == 0) {
        return()
      }

      # Ensure it's a list (even if single obj)
      if (!is.list(updates)) {
        updates <- list(updates)
      }

      projId <- activeProjectId()
      filePath <- currentFile()
      if (is.null(projId) || is.null(filePath)) {
        return()
      }

      cmts <- loadComments(projId, filePath)
      data_changed <- FALSE

      for (u in updates) {
        # Safety: only process if u is list/df and has 'id'
        if (!is.list(u) || is.null(u$id)) {
          next
        }

        for (i in seq_along(cmts)) {
          if (
            is.list(cmts[[i]]) && !is.null(cmts[[i]]$id) && cmts[[i]]$id == u$id
          ) {
            # Explicit integer coercion
            cmts[[i]]$startRow <- as.integer(u$startRow)
            cmts[[i]]$startCol <- as.integer(u$startCol)
            cmts[[i]]$endRow <- as.integer(u$endRow)
            cmts[[i]]$endCol <- as.integer(u$endCol)
            data_changed <- TRUE
            cat(
              "💾 Updated comment",
              u$id,
              "→ R[",
              u$startRow,
              ",",
              u$startCol,
              "]-[",
              u$endRow,
              ",",
              u$endCol,
              "]\n"
            )
            break
          }
        }
      }

      if (data_changed) {
        saveComments(projId, filePath, cmts)
        cat(
          "✅ Synced",
          length(updates),
          "comment(s) to disk for",
          filePath,
          "\n"
        )
      } else {
        cat("ℹ️  No coordinate changes needed\n")
      }
    },
    ignoreInit = TRUE
  )

  # --- CRITICAL: Render Markers on File Load or Editor Ready ---
  observeEvent(
    {
      list(currentFile(), input$aceEditorReady, input$toggleReviewPane)
    },
    {
      req(activeProjectId(), currentFile())

      # Load data
      cmts <- loadComments(activeProjectId(), currentFile())

      # Send to JS with Force=TRUE to ensure anchors are reset to disk state on file load
      session$sendCustomMessage(
        "renderCommentMarkers",
        list(
          comments = cmts,
          force = TRUE
        )
      )

      # Trigger sidebar refresh without full reload
      commentUpdate(commentUpdate() + 1)
    }
  )

  # ---------------- REWORKED SYNCTEX LOGIC ----------------
  observeEvent(input$syncTexClick, {
    req(input$syncTexClick)

    # 1. Capture Inputs
    click_page <- input$syncTexClick$page
    click_x <- input$syncTexClick$x
    click_y <- input$syncTexClick$y

    # 2. Validation: Ensure Synctex file exists
    uid <- isolate(user_session$user_info$user_id)
    if (is.null(uid)) {
      return()
    } # Should not happen if authenticated

    uCompiledDir <- getUserCompiledDir(uid)
    synctex_file <- file.path(uCompiledDir, "output.synctex.gz")

    if (!file.exists(synctex_file)) {
      showTablerAlert(
        "warning",
        "SyncTeX unavailable",
        "Please compile with SyncTeX enabled first.",
        5000
      )
      return()
    }

    # 3. Run Synctex in Docker
    tryCatch(
      {
        res <- processx::run(
          "docker",
          args = c(
            "run",
            "--rm",
            "-v",
            paste0(normalizePath(uCompiledDir, winslash = "/"), ":/compiled"),
            "-w",
            "/compiled",
            "texlive/texlive",
            "synctex",
            "edit",
            "-o",
            paste0(click_page, ":", click_x, ":", click_y, ":output.pdf")
          ),
          error_on_status = FALSE
        )

        output_str <- res$stdout

        # 4. Parse Output Robustly
        lines <- unlist(strsplit(output_str, "\n"))
        input_line <- grep("^Input:", lines, value = TRUE)
        line_num_line <- grep("^Line:", lines, value = TRUE)

        if (length(input_line) > 0 && length(line_num_line) > 0) {
          # Extract raw values
          raw_file <- sub("^Input:", "", input_line[1])
          raw_line <- sub("^Line:", "", line_num_line[1])

          # Clean path (remove ./ prefix if present)
          detected_file <- trimws(sub("^\\./", "", raw_file))
          target_line <- as.integer(trimws(raw_line))

          if (nzchar(detected_file) && !is.na(target_line) && target_line > 0) {
            # 5. Path Resolution Strategy
            projDir <- getActiveProjectDir()

            # Get all project files
            all_files <- list.files(projDir, recursive = TRUE)

            # --- CRITICAL FIX: Strictly Exclude compiled_cache from resolution ---
            # This ensures we NEVER match the temporary backup files
            all_files <- all_files[!grepl("^compiled_cache/|/\\.", all_files)]
            # ---------------------------------------------------------------------

            # Check direct match first
            final_rel_path <- NULL

            if (detected_file %in% all_files) {
              final_rel_path <- detected_file
            } else {
              # Fallback: Match by basename (e.g. if Docker path is absolute or different)
              matches <- grep(
                paste0(basename(detected_file), "$"),
                all_files,
                value = TRUE
              )
              if (length(matches) > 0) {
                # Pick the shortest match (usually the one in root) to avoid confusion
                matches <- matches[order(nchar(matches))]
                final_rel_path <- matches[1]
              }
            }

            if (!is.null(final_rel_path)) {
              # Force close any active file preview (fallback to editor) ---
              # We pass final_rel_path so the sidebar highlights the correct file immediately
              session$sendCustomMessage(
                "hideFilePreview",
                list(path = final_rel_path)
              )

              # 6. Execute Jump
              if (currentFile() != final_rel_path) {
                # Load file via JS trigger (handles editor mode, content, etc.)
                shinyjs::runjs(sprintf(
                  "if(window.Shiny) Shiny.setInputValue('fileClick', {path: '%s', isEditable: true, gotoLine: %d, context: 'synctex', nonce: Math.random()}, {priority: 'event'});",
                  final_rel_path,
                  target_line - 1
                ))
              } else {
                # Same file: Just scroll
                session$sendCustomMessage(
                  'aceGoTo',
                  list(line = target_line - 1)
                )
              }
            } else {}
          }
        }
      },
      error = function(e) {}
    )
  })

  # ---------------- FORWARD SEARCH (Editor -> PDF) ----------------
  observeEvent(input$editorSyncClick, {
    req(input$editorSyncClick)

    # 1. Collapse the Docker Console (maximize PDF height)
    # 2. Open the PDF Pane if it's currently hidden (maximize PDF visibility)
    shinyjs::runjs(
      "
      // 1. Vertical Split: Collapse Console
      if (window.consolePane) {
        window.consolePane.collapse();
      }
      
      // 2. Horizontal Split: Open PDF Sidebar if hidden
      if (typeof mainSplit !== 'undefined') {
        var sizes = mainSplit.getSizes();
        // If PDF pane (index 2) is less than 1% width, it's closed. Toggle it open.
        if (sizes[2] < 1) {
           window.togglePDF();
        }
      }
    "
    )
    # --------------------------------

    line <- as.integer(input$editorSyncClick$line)
    col <- as.integer(input$editorSyncClick$column)
    fileRelPath <- currentFile()

    if (is.null(fileRelPath) || fileRelPath == "") {
      return()
    }

    # Docker needs to see the file exactly as it was compiled.

    tryCatch(
      {
        uid <- isolate(user_session$user_info$user_id)
        if (is.null(uid)) {
          stop("User not logged in")
        }
        uCompiledDir <- getUserCompiledDir(uid)

        res <- processx::run(
          "docker",
          args = c(
            "run",
            "--rm",
            "-v",
            paste0(normalizePath(uCompiledDir, winslash = "/"), ":/compiled"),
            "-w",
            "/compiled",
            "texlive/texlive",
            "synctex",
            "view",
            # Pass column number explicitly: line:column:file
            "-i",
            paste0(line, ":", col, ":", fileRelPath),
            "-o",
            "output.pdf"
          ),
          error_on_status = FALSE
        )

        output_str <- res$stdout

        # Parse Result
        page_match <- regmatches(
          output_str,
          regexec("Page:([0-9]+)", output_str)
        )[[1]]
        x_match <- regmatches(
          output_str,
          regexec("x:([0-9\\.]+)", output_str)
        )[[1]]
        y_match <- regmatches(
          output_str,
          regexec("y:([0-9\\.]+)", output_str)
        )[[1]]

        if (length(page_match) > 1) {
          target_page <- as.numeric(page_match[2])
          target_x <- as.numeric(x_match[2])
          target_y <- as.numeric(y_match[2])

          # Send to Viewer
          session$sendCustomMessage(
            "syncPdfView",
            list(
              page = target_page,
              x = target_x,
              y = target_y
            )
          )
        } else {}
      },
      error = function(e) {}
    )
  })

  # -------------------- SERVER-SIDE CHKTEX LINTER (MERGED) --------------------
  lint_trigger <- reactive({
    input$sourceEditor
  }) %>%
    debounce(1000)
  observeEvent(lint_trigger(), {
    req(activeProjectId())
    req(currentFile())

    # 1. Only run on .tex files
    if (!grepl("\\.tex$", currentFile(), ignore.case = TRUE)) {
      lintAnnotations(list()) # Clear linter notes
      # But KEEP persistent compile notes visible
      session$sendCustomMessage("setAnnotations", compileAnnotations())
      return()
    }

    projDir <- getActiveProjectDir()

    # 2. Write to a temporary hidden file
    actual_filename <- basename(currentFile())
    temp_lint_filename <- paste0(".lint_", actual_filename)
    temp_lint_path <- file.path(projDir, temp_lint_filename)

    tryCatch(
      {
        writeLines(input$sourceEditor, temp_lint_path)
      },
      error = function(e) return()
    )

    # 3. Construct Docker command pointing to the TEMP file
    fmt <- "%l|%c|%d|%k|%m\n"
    docker_args <- c(
      "run",
      "--rm",
      "-v",
      paste0(normalizePath(projDir), ":/project"),
      "-w",
      "/project",
      "texlive/texlive",
      "chktex",
      "-q",
      "-v0",
      "-f",
      fmt,
      temp_lint_filename
    )

    output_raw <- tryCatch(
      {
        res <- processx::run("docker", docker_args, error_on_status = FALSE)
        res$stdout
      },
      error = function(e) ""
    )

    # 4. Clean up the temp file
    if (file.exists(temp_lint_path)) {
      unlink(temp_lint_path)
    }

    # 5. Parse Output
    annotations <- list()
    if (nzchar(output_raw)) {
      lines <- strsplit(output_raw, "\n")[[1]]
      for (line in lines) {
        parts <- strsplit(line, "\\|")[[1]]
        if (length(parts) >= 5) {
          row <- as.integer(parts[1]) - 1
          col <- as.integer(parts[2]) - 1

          # Handle "Warning", "Error", "Message" strings
          kind_str <- trimws(parts[4])
          kind_char <- toupper(substr(kind_str, 1, 1))
          type <- switch(
            kind_char,
            "E" = "error",
            "W" = "warning",
            "M" = "info",
            "info"
          )

          msg <- parts[5]

          annotations[[length(annotations) + 1]] <- list(
            row = row,
            column = col,
            text = msg,
            type = type
          )
        }
      }
    }

    # 6. UPDATE STATE AND MERGE
    lintAnnotations(annotations)

    # Retrieve persisted compile annotations
    current_compile <- isolate(compileAnnotations())

    # Combine both lists
    combined_anns <- c(current_compile, annotations)

    session$sendCustomMessage("setAnnotations", combined_anns)
  })

  # ----------------------------- CHAT HELPERS -----------------------------

  # Securely load chat data for a project
  loadProjectChat <- function(projId) {
    req(projId)

    uid <- isolate(user_session$user_info$user_id)
    if (is.null(uid)) {
      return(list(meta = list(), participants = list(), messages = list()))
    }

    pDir <- getUserProjectDir(uid)
    if (is.null(pDir)) {
      return(list(meta = list(), participants = list(), messages = list()))
    }

    chatFile <- file.path(pDir, projId, "chat_files", "chat.json")

    if (!file.exists(chatFile)) {
      return(list(
        meta = list(created = as.character(Sys.time())),
        participants = list(),
        messages = list()
      ))
    }
    tryCatch(
      {
        jsonlite::fromJSON(chatFile, simplifyVector = FALSE)
      },
      error = function(e) {
        list(meta = list(), participants = list(), messages = list())
      }
    )
  }

  # Save chat data with basic file locking to prevent overwrite conflicts
  saveProjectChat <- function(projId, chatData) {
    req(projId)

    uid <- isolate(user_session$user_info$user_id)
    if (is.null(uid)) {
      return(FALSE)
    }
    pDir <- getUserProjectDir(uid)
    if (is.null(pDir)) {
      return(FALSE)
    }

    chatFile <- file.path(pDir, projId, "chat_files", "chat.json")

    # Ensure directory exists
    if (!dir.exists(dirname(chatFile))) {
      dir.create(dirname(chatFile), recursive = TRUE)
    }

    lockFile <- paste0(chatFile, ".lock")
    i <- 0
    while (file.exists(lockFile) && i < 10) {
      Sys.sleep(0.1)
      i <- i + 1
    }
    file.create(lockFile)
    on.exit(unlink(lockFile))
    tryCatch(
      {
        jsonlite::write_json(
          chatData,
          chatFile,
          auto_unbox = TRUE,
          pretty = TRUE
        )
        return(TRUE)
      },
      error = function(e) return(FALSE)
    )
  }

  # Save uploaded chat files to a project-specific directory
  saveChatAttachments <- function(projId, files) {
    req(files)

    uid <- isolate(user_session$user_info$user_id)
    if (is.null(uid)) {
      return(list())
    }
    pDir <- getUserProjectDir(uid)

    # Create directory: projects/{projId}/chat_files
    uploadDir <- file.path(pDir, projId, "chat_files")
    if (!dir.exists(uploadDir)) {
      dir.create(uploadDir, recursive = TRUE)
    }

    savedPaths <- list()

    for (i in seq_len(nrow(files))) {
      # Generate unique name to prevent overwrites
      ext <- tools::file_ext(files$name[i])
      newFileName <- paste0(format(Sys.time(), "%Y%m%d%H%M%S_"), i, ".", ext)
      destPath <- file.path(uploadDir, newFileName)

      file.copy(files$datapath[i], destPath)

      # Store relative path for portability
      savedPaths[[i]] <- list(
        name = files$name[i],
        path = file.path("chat_files", newFileName), # Relative to project root
        type = files$type[i],
        size = files$size[i]
      )
    }
    return(savedPaths)
  }

  # ==============================================================================
  #                               CHAT SERVER LOGIC
  # ==============================================================================

  # 1. Reactive State -----------------------------------------------------------
  chatPaneVisible <- reactiveVal(FALSE)
  lastChatReadTime <- reactiveVal(as.numeric(Sys.time()))

  # Holds temporary state for file uploads and editing
  chatState <- reactiveValues(
    pendingAttachments = NULL, # Dataframe of files waiting to be sent
    editingMsgId = NULL # ID of the message currently being edited (NULL = normal mode)
  )

  # 2. Toggle Chat Pane Visibility ----------------------------------------------
  observeEvent(input$toggleChatPane, {
    val <- input$toggleChatPane
    newState <- if (is.logical(val)) val else !chatPaneVisible()
    chatPaneVisible(newState)

    if (newState) {
      lastChatReadTime(as.numeric(Sys.time()))
    } else {}
  })

  # 3. Data Polling (Real-time updates) -----------------------------------------
  chatDataReactive <- reactive({
    projId <- activeProjectId()
    if (is.null(projId)) {
      return(NULL)
    }

    # Poll file every 3 seconds
    invalidateLater(3000, session)

    loadProjectChat(projId)
  })

  # 4. Attachment Handling ------------------------------------------------------
  # A. Capture Uploads
  observeEvent(input$chatFileUpload, {
    files <- input$chatFileUpload
    req(files)

    # Validation: Max 3 files, Max 5MB each
    if (nrow(files) > 3) {
      showTablerAlert("error", "Too many attachments", "Maximum 3 files allowed per message.", 5000)
      return()
    }
    if (any(files$size > 5 * 1024 * 1024)) {
      showTablerAlert("error", "Too big attachments", "All files must be under 5MB.", 5000)
      return()
    }

    chatState$pendingAttachments <- files
  })

  # B. Remove a pending attachment
  observeEvent(input$removeAttachment, {
    idx <- input$removeAttachment
    files <- chatState$pendingAttachments
    if (!is.null(files) && idx <= nrow(files)) {
      chatState$pendingAttachments <- files[-idx, , drop = FALSE]
      if (nrow(chatState$pendingAttachments) == 0) {
        chatState$pendingAttachments <- NULL
      }
    }
  })

  # C. Render Preview Area (Above input box)
  output$chatAttachmentPreview <- renderUI({
    files <- chatState$pendingAttachments
    # Extra safety: Ensure it is actually a dataframe with rows
    if (is.null(files) || !is.data.frame(files) || nrow(files) == 0) {
      return(NULL)
    }

    div(
      class = "d-flex gap-2 mb-2 flex-wrap",
      lapply(1:nrow(files), function(i) {
        tags$span(
          class = "badge bg-blue-lt",
          files$name[i],
          tags$span(
            class = "ms-2 cursor-pointer",
            style = "cursor:pointer;",
            "×",
            onclick = sprintf(
              "Shiny.setInputValue('removeAttachment', %d, {priority:'event'})",
              i
            )
          )
        )
      })
    )
  })

  # 5. Message Actions (Edit / Delete) ------------------------------------------
  observeEvent(input$msgAction, {
    action <- input$msgAction$action
    msgId <- input$msgAction$id
    projId <- activeProjectId()
    user <- loadUserProfile()

    data <- loadProjectChat(projId)

    # Find message index
    idx <- which(sapply(data$messages, function(x) x$id == msgId))
    if (length(idx) == 0) {
      return()
    }

    msg <- data$messages[[idx]]

    # Security: Only owner can modify
    if (msg$senderId != user$userId) {
      showTablerAlert("warning", "Cannot edit", "You cannot modify this message.", 5000)
      return()
    }

    if (action == "delete") {
      # --- DELETE LOGIC ---
      data$messages[[idx]]$isDeleted <- TRUE
      data$messages[[idx]]$content <- "This message was deleted."
      data$messages[[idx]]$attachments <- list() # Clear files
      saveProjectChat(projId, data)
    } else if (action == "edit") {
      # --- EDIT SETUP ---
      chatState$editingMsgId <- msgId

      # Populate input with existing text
      updateTextAreaInput(
        session,
        "chatInputMsg",
        value = msg$content,
        placeholder = "Editing... (Press Enter to update)"
      )

      # Focus input
      shinyjs::runjs("document.getElementById('chatInputMsg').focus();")
    }
  })

  # 6. Sending Messages (New & Edit Commit) -------------------------------------
  # Listens to both the UI button and the JS 'Enter' key trigger
  observeEvent(
    {
      input$btnSendChat
      input$triggerSendChat
    },
    {
      txt <- input$chatInputMsg
      files <- chatState$pendingAttachments
      projId <- activeProjectId()
      user <- loadUserProfile()

      # Basic Validation
      hasText <- !is.null(txt) && nzchar(trimws(txt))
      hasFiles <- !is.null(files) && is.data.frame(files) && nrow(files) > 0

      # Allow empty text ONLY if we have files (for new messages)
      if (!hasText && !hasFiles) {
        return()
      }

      data <- loadProjectChat(projId)

      # --- BRANCH A: EDIT EXISTING MESSAGE ---
      if (!is.null(chatState$editingMsgId)) {
        idx <- which(sapply(data$messages, function(x) {
          x$id == chatState$editingMsgId
        }))

        if (length(idx) > 0) {
          if (!hasText) {
            # If user clears text during edit, treat as cancel or warn?
            # Here we assume text is required for edit.
            showTablerAlert("warning", "Empty message", "Message cannot be empty.", 5000)
            return()
          }

          data$messages[[idx]]$content <- trimws(txt)
          data$messages[[idx]]$isEdited <- TRUE
          saveProjectChat(projId, data)
        }

        # Reset Edit Mode
        chatState$editingMsgId <- NULL
        updateTextAreaInput(
          session,
          "chatInputMsg",
          value = "",
          placeholder = "Type a message..."
        )
      } else {
        # --- BRANCH B: SEND NEW MESSAGE ---

        # 1. Process Attachments
        savedFiles <- list()
        if (hasFiles) {
          savedFiles <- saveChatAttachments(projId, files)
        }

        # 2. Construct Message
        newMsg <- list(
          id = paste0("msg_", as.numeric(Sys.time())),
          senderId = user$userId,
          senderName = user$username,
          senderAvatar = user$profilePicture,
          content = if (hasText) trimws(txt) else "",
          attachments = savedFiles,
          timestamp = as.character(Sys.time()),
          status = "delivered",
          readBy = list(user$userId),
          isEdited = FALSE,
          isDeleted = FALSE
        )

        data$messages <- c(data$messages, list(newMsg))
        saveProjectChat(projId, data)

        # 3. Cleanup
        updateTextAreaInput(session, "chatInputMsg", value = "")
        chatState$pendingAttachments <- NULL
        shinyjs::reset("chatFileUpload") # Clear file input

        # 4. Analytics
        recordDailyActivity("chat", list(projectId = projId))
      }
    },
    ignoreInit = TRUE
  )

  # 7. Typing Indicators --------------------------------------------------------
  observeEvent(input$userTyping, {
    req(activeProjectId())
    user <- loadUserProfile()

    uid <- isolate(user_session$user_info$user_id)
    if (is.null(uid)) {
      return()
    }
    pDir <- getUserProjectDir(uid)
    if (is.null(pDir)) {
      return()
    }

    # Define path
    typingFile <- file.path(pDir, activeProjectId(), "chat_files", "typing.txt")

    # FIX: Ensure directory exists before writing
    dir.create(dirname(typingFile), recursive = TRUE, showWarnings = FALSE)

    # Write lock file
    writeLines(
      paste(user$userId, as.numeric(Sys.time()), sep = "|"),
      typingFile
    )
  })

  # 8. Render Message Stream (Fixed Links & Navigation)
