    session$sendCustomMessage("toggleHistoryView", TRUE)

    if (length(manifest) > 0) {
      latestId <- manifest[[1]]$id
      shinyjs::delay(200, {
        shinyjs::runjs(sprintf("loadHistoryItem('%s')", latestId))
      })
