        pDir <- getUserProjectDir(uid)
        cachePdf <- file.path(
          pDir,
          activeProjectId(),
          "compiled_cache",
          "output.pdf"
        )
        if (file.exists(cachePdf)) {
          pdfPath <- cachePdf
        } else {
          stop("No PDF available. Please compile the project first.")
        }
      }
      file.copy(pdfPath, file)
    },
    contentType = "application/pdf"
  )
